# ── 인물 카드 헬퍼 ──────────────────────────────────────────────
def _fmt_gender(v: str) -> str:
    t = (v or "").strip()
    if t in ("남", "남자", "남성", "m", "M", "male", "Male", "♂"):
        return "남성"
    if t in ("여", "여자", "여성", "f", "F", "female", "Female", "♀"):
        return "여성"
    return t


def _fmt_age(v: str) -> str:
    t = (v or "").strip()
    return f"{t}세" if t.isdigit() else t


def _character_cards(characters: dict) -> str:
    from .sheet_bible import CHAR_SUBS
    cards = []
    for name, subs in characters.items():
        tags = []
        if subs.get("포지션"):
            tags.append(subs["포지션"])
        if subs.get("성별"):
            tags.append(_fmt_gender(subs["성별"]))
        if subs.get("나이"):
            tags.append(_fmt_age(subs["나이"]))
        head = f"{name}" + (f" — {' · '.join(tags)}" if tags else "")
        lines = [f"■ {head}"]
        for k in CHAR_SUBS:
            if k in ("나이", "성별", "포지션"):
                continue
            if subs.get(k):
                lines.append(f"  - {k}: {subs[k]}")
        for k, v in subs.items():
            if k not in CHAR_SUBS and v:
                lines.append(f"  - {k}: {v}")
        cards.append("\n".join(lines))
    return "\n\n".join(cards)


# ── 작품 바이블 블록 (노션→시트) ─────────────────────────────────
def storyboard_bible_block(bible: dict | None, target_episode: int | None = None) -> str:
    if not bible:
        return ""
    te = target_episode or bible.get("current_episode")
    parts = []
    if bible.get("forbidden"):
        parts.append("## ⛔ 금지사항 (스토리보드에서도 절대 위반 금지 — 비주얼로도 그리지 마라)\n"
                     + bible["forbidden"])
    if te:
        parts.append(f"## 지금 시점: {te}화 — 이 화 '대본'의 장면을 스토리보드로 만든다. "
                     "(대본에 있는 것만 옮긴다. 개요·줄거리로 내용을 보태지 마라.)")
    if bible.get("logline"):
        parts.append("## 로그라인\n" + bible["logline"])
    if bible.get("emotion"):
        parts.append("## 핵심정서\n" + bible["emotion"])
    if bible.get("target"):
        parts.append("## 타겟층\n" + bible["target"])
    ep = bible.get("episode_plan") or {}
    if ep:
        rows = []
        for arc, v in ep.items():
            seg = " · ".join(x for x in [v.get("구간"), v.get("화수")] if x)
            row = "■ " + arc + (f" ({seg})" if seg else "")
            if v.get("핵심사건"):
                row += f"\n  - 핵심사건: {v['핵심사건']}"
            rows.append(row)
        parts.append("## 회차분배 (전체 구성 — 이 흐름·핵심사건 밖으로 벗어나지 마라)\n" + "\n".join(rows))
    if bible.get("characters"):
        parts.append("## 등장인물 (이름·호칭·외형/의상 일관성을 이 설정에 맞춰라 — 새 인물·설정 추가 금지)\n"
                     + _character_cards(bible["characters"]))
    if not parts:
        return ""
    return ("\n\n# [작품 바이블] " + (bible.get("title") or "") + " (노션 동기화 내용)\n"
            + "아래는 이 작품의 확정 설정이다. 스토리보드가 이 설정·금지사항·인물·회차 흐름과 어긋나지 않게 하라.\n\n"
            + "\n\n".join(parts))


